import{_ as e,o as s,c as n,a2 as t}from"./chunks/framework.BFZItJIV.js";const u=JSON.parse('{"title":"ACP 线程支持","description":"","frontmatter":{},"headers":[],"relativePath":"channel/acp-threads.md","filePath":"channel/acp-threads.md","lastUpdated":null}'),i={name:"channel/acp-threads.md"};function d(l,a,o,p,r,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="acp-线程支持" tabindex="-1">ACP 线程支持 <a class="header-anchor" href="#acp-线程支持" aria-label="Permalink to &quot;ACP 线程支持&quot;">​</a></h1><p>Clawline 支持 <a href="https://docs.openclaw.ai/tools/acp-agents" target="_blank" rel="noreferrer">ACP（Agent Collaboration Protocol）</a> 线程，允许 Agent 在对话中启动子 Agent 会话。用户可以通过 <code>/acp spawn</code> 命令创建持久化或临时的子 Agent 线程。</p><h2 id="什么是-acp" tabindex="-1">什么是 ACP <a class="header-anchor" href="#什么是-acp" aria-label="Permalink to &quot;什么是 ACP&quot;">​</a></h2><p>ACP 允许一个 OpenClaw Agent 启动另一个 Agent（如 Claude Code）作为子代理执行特定任务。子代理的消息通过 thread 机制与主对话隔离，在客户端展示为折叠的会话卡片。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><p>在 Clawline 聊天中发送 ACP 命令：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/acp spawn claude --mode persistent --thread auto</span></span></code></pre></div><h3 id="常用参数" tabindex="-1">常用参数 <a class="header-anchor" href="#常用参数" aria-label="Permalink to &quot;常用参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>claude</code></td><td>子 Agent 后端（使用官方 <code>@agentclientprotocol/claude-agent-acp</code>）</td></tr><tr><td><code>--mode persistent</code></td><td>持久化模式，会话在对话结束后保留</td></tr><tr><td><code>--mode ephemeral</code></td><td>临时模式，任务完成后自动关闭</td></tr><tr><td><code>--thread auto</code></td><td>自动创建线程，消息按线程分组</td></tr><tr><td><code>--cwd /path/to/dir</code></td><td>指定子 Agent 的工作目录</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 启动 Claude 持久会话</span></span>
<span class="line"><span>/acp spawn claude --mode persistent --thread auto</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 启动临时任务</span></span>
<span class="line"><span>/acp spawn claude --mode ephemeral --thread auto</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 指定工作目录</span></span>
<span class="line"><span>/acp spawn claude --mode persistent --thread auto --cwd /Users/me/project</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 关闭会话</span></span>
<span class="line"><span>/acp close</span></span></code></pre></div><h2 id="技术实现" tabindex="-1">技术实现 <a class="header-anchor" href="#技术实现" aria-label="Permalink to &quot;技术实现&quot;">​</a></h2><h3 id="virtual-threadid-机制" tabindex="-1">Virtual ThreadId 机制 <a class="header-anchor" href="#virtual-threadid-机制" aria-label="Permalink to &quot;Virtual ThreadId 机制&quot;">​</a></h3><p>Clawline 采用虚拟线程 ID 来支持 ACP 的 <code>--thread auto</code> 功能：</p><ol><li><strong>生成</strong>：当入站消息到达时，插件为每个对话生成唯一的 <code>clawline-thread-\${UUID}</code> 作为虚拟线程 ID</li><li><strong>复用</strong>：同一对话的后续消息会复用已有 ACP binding 的 threadId，保持会话连续性</li><li><strong>绑定</strong>：threadId 设置为 <code>MessageThreadId</code>，使 ACP 运行时将 placement 解析为 <code>&quot;current&quot;</code>（复用当前线程，而非创建子线程）</li></ol><h3 id="session-binding-生命周期" tabindex="-1">Session Binding 生命周期 <a class="header-anchor" href="#session-binding-生命周期" aria-label="Permalink to &quot;Session Binding 生命周期&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户消息 → 生成/复用 virtualThreadId</span></span>
<span class="line"><span>        → 设置 MessageThreadId</span></span>
<span class="line"><span>        → ACP 运行时创建 session binding</span></span>
<span class="line"><span>        → binding 存储 conversationId = &quot;thread:{threadId}&quot;</span></span>
<span class="line"><span>        → 子 Agent 回复通过 binding 路由到正确的 threadId</span></span></code></pre></div><p>插件内维护一个 <strong>内存态 SessionBindingAdapter</strong>，支持按 conversationId、sessionKey、bindingId 三种索引查询。</p><h3 id="回复路由" tabindex="-1">回复路由 <a class="header-anchor" href="#回复路由" aria-label="Permalink to &quot;回复路由&quot;">​</a></h3><p>子 Agent 的回复通过两条路径之一发送到客户端：</p><ol><li><strong>Outbound Adapter</strong>（<code>dispatch-acp-delivery</code>）：读取 <code>MessageThreadId</code>，在回复中附带 <code>threadId</code></li><li><strong>Reply Dispatcher</strong>（持久模式回复）：每次投递时延迟解析 <code>threadId</code>，确保能找到 dispatch 期间新创建的 binding</li></ol><p>两条路径均支持 <code>threadId</code> 透传，客户端收到后将消息归入对应的线程卡片。</p><h3 id="消息持久化" tabindex="-1">消息持久化 <a class="header-anchor" href="#消息持久化" aria-label="Permalink to &quot;消息持久化&quot;">​</a></h3><p>带有 <code>threadId</code> 的消息会持久化到 Supabase 的 <code>cl_messages.thread_id</code> 字段，页面刷新后客户端从远程同步消息时能恢复线程分组。</p><h2 id="客户端展示" tabindex="-1">客户端展示 <a class="header-anchor" href="#客户端展示" aria-label="Permalink to &quot;客户端展示&quot;">​</a></h2><h3 id="threadsessioncard" tabindex="-1">ThreadSessionCard <a class="header-anchor" href="#threadsessioncard" aria-label="Permalink to &quot;ThreadSessionCard&quot;">​</a></h3><p>ACP session 在客户端以可折叠的卡片形式展示：</p><ul><li>标题栏显示：<code>ACP Session · agent名 · mode</code>（如 persistent/ephemeral）</li><li>包含该线程的所有消息（Agent 回复 + 用户发送）</li><li>活跃 session 显示关闭按钮（发送 <code>/acp close</code>）</li><li>呼吸灯动画标识活跃状态</li></ul><h3 id="acp-session-bar" tabindex="-1">ACP Session Bar <a class="header-anchor" href="#acp-session-bar" aria-label="Permalink to &quot;ACP Session Bar&quot;">​</a></h3><p>输入框上方显示 session 切换条（仅在有 ACP session 时出现）：</p><ul><li>水平滚动的 chip 列表</li><li>每个 chip 显示：mode + sessionId 片段 + 消息数</li><li>点击 chip 切换 <code>activeThreadId</code>，后续发送的消息自动路由到该 session</li><li>当前活跃 session 高亮显示</li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>ACP 线程功能需要以下条件：</p><ol><li><strong>OpenClaw 配置</strong>：在 <code>~/.openclaw/openclaw.json</code> 的 <code>plugins</code> 中启用 <code>acpx</code> 后端</li><li><strong>子 Agent 安装</strong>：确保 <code>@agentclientprotocol/claude-agent-acp</code> 已安装</li><li><strong>API 密钥</strong>：子 Agent（如 Claude）需要对应的 API 密钥环境变量</li></ol><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugins&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;acpx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><blockquote><p>使用自定义 API URL 时，需要在启动环境中设置 <code>ANTHROPIC_BASE_URL</code> 和 <code>ANTHROPIC_API_KEY</code> 环境变量。如果通过 launchd 管理进程，需要在 plist 文件中添加这些环境变量。</p></blockquote><h2 id="断点续传" tabindex="-1">断点续传 <a class="header-anchor" href="#断点续传" aria-label="Permalink to &quot;断点续传&quot;">​</a></h2><p>Clawline 的流式输出支持跨断线恢复（断点续传）：</p><ul><li>每个正在进行的流按 <code>chatId::agentId</code> 键存储累积文本</li><li>客户端重连时，如果 URL 中携带 <code>agentId</code>，服务端发送 <code>stream.resume</code> 事件</li><li>已完成的流通过 <code>markStreamCompleted()</code> 标记，30 分钟后自动清理</li></ul>`,39)])])}const g=e(i,[["render",d]]);export{u as __pageData,g as default};
